// Demo mode: makes the Todo app fully functional in the browser with no backend.
// Overrides axios's network adapter to read/write todos in localStorage so the
// hosted demo supports real add / edit / delete with persistence.
import axios from "axios";

const KEY = "demo_todos_v1";
const SEED = [
  { id: 1, title: "Ship the Aqar Syria case study" },
  { id: 2, title: "Deploy Dr.pets demo to production" },
  { id: 3, title: "Review the Alboraq live-chat PR" },
  { id: 4, title: "Prep for the senior engineer interview" },
];

function load() {
  try {
    const raw = localStorage.getItem(KEY);
    if (raw) return JSON.parse(raw);
  } catch (_) {}
  localStorage.setItem(KEY, JSON.stringify(SEED));
  return [...SEED];
}
function save(todos) {
  localStorage.setItem(KEY, JSON.stringify(todos));
}
function ok(data) {
  return Promise.resolve({ data, status: 200, statusText: "OK", headers: {}, config: {} });
}

axios.defaults.adapter = function (config) {
  const url = config.url || "";
  let body = {};
  try { body = config.data ? JSON.parse(config.data) : {}; } catch (_) { body = config.data || {}; }
  let todos = load();

  if (url.includes("/todos/index")) return ok({ data: todos });

  if (url.includes("/todos/store")) {
    const id = todos.length ? Math.max(...todos.map((t) => t.id)) + 1 : 1;
    const todo = { id, title: body.title };
    todos.push(todo);
    save(todos);
    return ok({ data: todo, message: "created" });
  }

  const upd = url.match(/\/todos\/update\/(\d+)/);
  if (upd) {
    const id = Number(upd[1]);
    todos = todos.map((t) => (t.id === id ? { ...t, title: body.title } : t));
    save(todos);
    return ok({ data: { id, title: body.title }, message: "updated" });
  }

  const del = url.match(/\/todos\/destroy\/(\d+)/);
  if (del) {
    const id = Number(del[1]);
    todos = todos.filter((t) => t.id !== id);
    save(todos);
    return ok({ data: {}, message: "deleted" });
  }

  return ok({ data: [] });
};
